// Ken Burns: download image → inline FFmpeg zoompan → return clip path.
// Register-aware motion presets. Cap: zoom velocity ≤ 0.001 u/frame @30fps.
// Scene-position routing: scene_number===1 = 'hero', else cycle through
// the register's 3 regular presets by scene_number % 3.

const scene = $input.first().json;
const topicId = $('Webhook Trigger').first().json.body.topic_id;
const sceneNum = String(scene.scene_number).padStart(3, '0');
const duration = scene.audio_duration_ms ? (scene.audio_duration_ms / 1000).toFixed(2) : '7';
const register = scene.production_register || null;
// ── Per-register LUT3D path (replaces R3 eq+colorbalance soft-LUT chain)
const LUT_BASE = '/tmp/production/luts';
const LUT_MAP = {
  REGISTER_01_ECONOMIST: LUT_BASE + '/register_01_economist.cube',
  REGISTER_02_PREMIUM:   LUT_BASE + '/register_02_premium.cube',
  REGISTER_03_NOIR:      LUT_BASE + '/register_03_noir.cube',
  REGISTER_04_SIGNAL:    LUT_BASE + '/register_04_signal.cube',
  REGISTER_05_ARCHIVE:   LUT_BASE + '/register_05_archive.cube'
};
// Archive era sub-LUTs — pick based on register_era_detected (stamped on topic)

// ── Per-register signature overlay PNG (hero scene only — scene_number === 1)
const SIG_OVERLAY_BASE = '/tmp/production/overlays';
const SIG_OVERLAY_MAP = {
  REGISTER_01_ECONOMIST: SIG_OVERLAY_BASE + '/register_01_economist.png',
  REGISTER_02_PREMIUM:   SIG_OVERLAY_BASE + '/register_02_premium.png',
  REGISTER_03_NOIR:      SIG_OVERLAY_BASE + '/register_03_noir.png',
  REGISTER_04_SIGNAL:    SIG_OVERLAY_BASE + '/register_04_signal.png',
  REGISTER_05_ARCHIVE:   SIG_OVERLAY_BASE + '/register_05_archive.png'
};
const SIG_ARCHIVE_ERA = {
  '1920s': SIG_OVERLAY_BASE + '/register_05_archive_1920s.png',
  '1960s': SIG_OVERLAY_BASE + '/register_05_archive_1960s.png',
  '1980s': SIG_OVERLAY_BASE + '/register_05_archive_1980s.png',
  '2000s': SIG_OVERLAY_BASE + '/register_05_archive_2000s.png'
};

const ARCHIVE_ERA_MAP = {
  '1920s': LUT_BASE + '/register_05_archive_1920s.cube',
  '1960s': LUT_BASE + '/register_05_archive_1960s.cube',
  '1980s': LUT_BASE + '/register_05_archive_1980s.cube',
  '2000s': LUT_BASE + '/register_05_archive_2000s.cube',
  'modern': LUT_BASE + '/register_05_archive.cube'
};

// Fetch topic's era once (inline HTTP — lightweight, once per scene is fine for 161 scenes)
let registerEra = null;
if (register === 'REGISTER_05_ARCHIVE') {
  try {
    const eraResp = await this.helpers.httpRequest({
      method: 'GET',
      url: `${$env.SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}&select=register_era_detected`,
      headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}` }
    });
    const parsed = Array.isArray(eraResp) ? eraResp : (typeof eraResp === 'string' ? JSON.parse(eraResp) : eraResp);
    if (parsed && parsed[0]) { registerEra = parsed[0].register_era_detected || null; }
  } catch (e) { /* era lookup is optional */ }
}

let lutPath = null;
if (register === 'REGISTER_05_ARCHIVE' && registerEra && ARCHIVE_ERA_MAP[registerEra]) {
  lutPath = ARCHIVE_ERA_MAP[registerEra];
} else if (register && LUT_MAP[register]) {
  lutPath = LUT_MAP[register];
}

const imgPath = `/tmp/production/kb_${topicId}_${sceneNum}.png`;
const clipPath = `/tmp/production/kb_${topicId}_${sceneNum}.mp4`;
const fps = 30;
const frames = Math.max(30, Math.round(parseFloat(duration) * fps));

// ── Per-register preset library ────────────────────────────────────────────
// Each preset is a zoompan filter string. {D}=frames.
// Z/X/Y expressions use 'on' (frame index) to produce smooth, capped motion.
//
// Presets mapped to register × scene_position. 'hero' is the first scene;
// regular scenes cycle regular_a/b/c.

const PRESETS = {
  // R01 Economist — slow push default, documentary feel (0.0015 u/frame)
  REGISTER_01_ECONOMIST: {
    hero:       "zoompan=z='if(eq(on,0),1.15,max(1.0,1.15-on*0.0005))':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_a:  "zoompan=z='min(1.15,1.0+on*0.0005)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_b:  "zoompan=z='min(1.08,1.0+on*0.0003)':d=${frames}:x='min(iw-iw/zoom,(iw-iw/zoom)*on/${frames})':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_c:  "zoompan=z='min(1.10,1.02+on*0.00025)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30"
  },
  // R02 Premium — breath-paced, gentle (0.0008 u/frame)
  REGISTER_02_PREMIUM: {
    hero:       "zoompan=z='min(1.10,1.02+on*0.0003)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_a:  "zoompan=z='min(1.08,1.02+on*0.00025)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_b:  "zoompan=z='if(eq(on,0),1.08,max(1.02,1.08-on*0.0003))':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_c:  "zoompan=z='min(1.06,1.02+on*0.0002)':d=${frames}:x='max(0,(iw-iw/zoom)*(1-on/${frames}))':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30"
  },
  // R03 Noir — creeping, tense (0.0003 u/frame, very slow)
  REGISTER_03_NOIR: {
    hero:       "zoompan=z='min(1.08,1.0+on*0.00028)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_a:  "zoompan=z='min(1.04,1.0+on*0.00015)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_b:  "zoompan=z='min(1.06,1.02+on*0.00015)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)+on*0.3':s=1920x1080:fps=30",
    regular_c:  "zoompan=z=1.02:d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30"
  },
  // R04 Signal — precision, sharper pace (0.002 u/frame but shorter)
  REGISTER_04_SIGNAL: {
    hero:       "zoompan=z='min(1.12,1.0+on*0.0007)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_a:  "zoompan=z='min(1.08,1.0+on*0.0005)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_b:  "zoompan=z=1.0:d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_c:  "zoompan=z='min(1.06,1.0+on*0.0004)':d=${frames}:x='min(iw-iw/zoom,(iw-iw/zoom)*on/${frames})':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30"
  },
  // R05 Archive — Ken Burns pan+zoom (classic documentary motion)
  REGISTER_05_ARCHIVE: {
    hero:       "zoompan=z='min(1.18,1.05+on*0.0007)':d=${frames}:x='min(iw-iw/zoom,(iw-iw/zoom)*on/${frames})':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_a:  "zoompan=z='min(1.15,1.05+on*0.0005)':d=${frames}:x='min(iw-iw/zoom,(iw-iw/zoom)*on/${frames})':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_b:  "zoompan=z='min(1.12,1.05+on*0.0003)':d=${frames}:x='max(0,(iw-iw/zoom)*(1-on/${frames}))':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30",
    regular_c:  "zoompan=z='if(eq(on,0),1.15,max(1.02,1.15-on*0.0005))':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30"
  }
};


// ── Per-register color grade ("soft LUT" — FFmpeg eq + colorbalance + curves)
// Applied AFTER zoompan in the filter chain. Real .cube LUTs can drop in later.
const GRADES = {
  // R01 Economist — muted documentary warmth
  REGISTER_01_ECONOMIST: "eq=contrast=1.05:saturation=0.88,colorbalance=rs=0.02:gs=0.00:bs=-0.02:rm=0.04:gm=0.00:bm=-0.03:rh=0.03:gh=0.01:bh=-0.04",
  // R02 Premium — golden Kodak Portra (teal shadows, amber highlights)
  REGISTER_02_PREMIUM: "eq=contrast=1.08:saturation=1.02:gamma=1.04,colorbalance=rs=-0.03:gs=-0.01:bs=0.06:rm=0.04:gm=0.02:bm=-0.03:rh=0.10:gh=0.05:bh=-0.08,curves=all='0/0 0.35/0.32 0.65/0.72 1/1'",
  // R03 Noir — desaturated bleach bypass, cold shadows, crushed blacks
  REGISTER_03_NOIR: "eq=contrast=1.18:saturation=0.55:brightness=-0.03:gamma=0.94,colorbalance=rs=-0.04:gs=0.00:bs=0.08:rm=0.00:gm=-0.02:bm=0.03:rh=0.03:gh=0.01:bh=-0.02,curves=all='0/0 0.18/0.10 0.55/0.55 0.85/0.92 1/1'",
  // R04 Signal — cool, high-contrast, clinical
  REGISTER_04_SIGNAL: "eq=contrast=1.14:saturation=0.95,colorbalance=rs=-0.04:gs=0.00:bs=0.08:rm=-0.02:gm=0.00:bm=0.05:rh=0.02:gh=0.04:bh=0.08,curves=all='0/0 0.25/0.20 0.75/0.80 1/1'",
  // R05 Archive — sepia warm-faded, lifted shadows, low saturation
  REGISTER_05_ARCHIVE: "eq=contrast=0.96:saturation=0.72:gamma=1.08:brightness=0.02,colorbalance=rs=0.06:gs=0.02:bs=-0.06:rm=0.08:gm=0.04:bm=-0.08:rh=0.10:gh=0.06:bh=-0.10"
};

const GRADE_FALLBACK = "eq=saturation=0.95";
const grade = (register && GRADES[register]) || GRADE_FALLBACK;

// ── Per-register overlay filters (film grain + vignette intensity per spec)
// Grain opacity matches video_production/README table: R01 8%, R02 6%, R03 12%, R04 5%, R05 15%.
// Vignette strength per register's cinematic rule.
const OVERLAYS = {
  REGISTER_01_ECONOMIST: "noise=alls=4:allf=t+u,vignette=angle=PI/5",
  REGISTER_02_PREMIUM:   "noise=alls=3:allf=t+u,vignette=angle=PI/4.5",
  REGISTER_03_NOIR:      "noise=alls=8:allf=t+u,vignette=angle=PI/3",
  REGISTER_04_SIGNAL:    "noise=alls=2:allf=t+u,vignette=angle=PI/6",
  REGISTER_05_ARCHIVE:   "noise=alls=10:allf=t+u,vignette=angle=PI/3.5"
};
const OVERLAY_FALLBACK = "vignette=angle=PI/5";
const overlays = (register && OVERLAYS[register]) || OVERLAY_FALLBACK;


// Fallback (no register): gentle push (matches old default zoom=in)
const FALLBACK = "zoompan=z='min(1.10,1.0+on*0.0004)':d=${frames}:x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':s=1920x1080:fps=30";

// Pick preset
let presetTemplate = null;
let presetName = 'fallback';
if (register && PRESETS[register]) {
  const lib = PRESETS[register];
  if (scene.scene_number === 1) {
    presetTemplate = lib.hero;
    presetName = 'hero';
  } else {
    const keys = ['regular_a', 'regular_b', 'regular_c'];
    const k = keys[(scene.scene_number - 2) % keys.length];
    presetTemplate = lib[k];
    presetName = k;
  }
} else {
  presetTemplate = FALLBACK;
}

const zoompan = presetTemplate.replace(/\${frames}/g, String(frames));

// Download image
const { execSync } = require('child_process');
try {
  execSync(`/usr/bin/curl -sL -o "${imgPath}" "${scene.image_url}"`, { timeout: 30000 });
} catch (e) {
  return [{ json: { success: false, scene_id: scene.id, scene_number: scene.scene_number, error: 'Image download failed: ' + e.message } }];
}

// Run Ken Burns inline (no shell script dependency)
// Resolve signature overlay (hero scene only)
let sigOverlayPath = null;
if (scene.scene_number === 1 && register) {
  if (register === 'REGISTER_05_ARCHIVE' && registerEra && SIG_ARCHIVE_ERA[registerEra]) {
    sigOverlayPath = SIG_ARCHIVE_ERA[registerEra];
  } else if (SIG_OVERLAY_MAP[register]) {
    sigOverlayPath = SIG_OVERLAY_MAP[register];
  }
}

let ffCmd;
if (sigOverlayPath) {
  // Hero scene with signature overlay — filter_complex with 2 inputs
  ffCmd = `/usr/bin/ffmpeg -y -loop 1 -i "${imgPath}" -i "${sigOverlayPath}" -filter_complex "[0:v]${vfChain}[g];[g][1:v]overlay=0:0:format=auto" -t ${duration} -c:v libx264 -pix_fmt yuv420p -preset slow -crf 18 -r 30 "${clipPath}"`;
} else {
  ffCmd = `/usr/bin/ffmpeg -y -loop 1 -i "${imgPath}" -vf "${vfChain}" -t ${duration} -c:v libx264 -pix_fmt yuv420p -preset slow -crf 18 -r 30 "${clipPath}"`;
}
try {
  execSync(ffCmd, { timeout: 180000, stdio: ['ignore','ignore','pipe'] });
} catch (e) {
  try { execSync(`/bin/rm -f "${imgPath}"`); } catch(_) {}
  return [{ json: { success: false, scene_id: scene.id, scene_number: scene.scene_number, error: 'FFmpeg failed: ' + String(e.message || e).slice(0, 300), register, preset: presetName } }];
}

// Cleanup input image
try { execSync(`/bin/rm -f "${imgPath}"`); } catch(_) {}

return [{ json: {
  success: true,
  scene_id: scene.id,
  scene_number: scene.scene_number,
  clip_path: clipPath,
  duration: parseFloat(duration),
  register: register,
  preset: presetName,
  grade_applied: !!(register && GRADES[register]),
  overlays_applied: !!(register && OVERLAYS[register]),
  lut_used: lutPath || null,
  register_era: registerEra || null,
  signature_overlay_applied: !!sigOverlayPath
} }];
